insert into raw.av_news_sentiment ("symbol", "url", "record", "source_s3_key") values ('KO', 'https://www.diageo.com/en/investors/results-reports-and-events/annual-report-2024', '{"url": "https://www.diageo.com/en/investors/results-reports-and-events/annual-report-2024", "title": "Annual Report 2024", "source": "Diageo", "topics": [{"topic": "earnings", "relevance_score": "0.928320"}, {"topic": "economy_macro", "relevance_score": "0.713387"}, {"topic": "finance", "relevance_score": "0.630343"}, {"topic": "retail_wholesale", "relevance_score": "0.643027"}], "authors": [], "summary": "Diageo''s 2024 Annual Report highlights its position as a global leader in Total Beverage Alcohol (TBA) and its ambition to be a top-performing consumer products company. The report details financial and non-financial performance, strategic priorities for growth, and sustainability efforts under its \"Spirit of Progress\" plan. Key executives discuss challenges from the past year and the attractive long-term growth prospects of the TBA industry, particularly in spirits and premium segments.", "banner_image": null, "source_domain": "Diageo", "time_published": "20241231T235959", "ticker_sentiment": [{"ticker": "DEO", "relevance_score": "1.000000", "ticker_sentiment_label": "Bullish", "ticker_sentiment_score": "0.452179"}, {"ticker": "STZ", "relevance_score": "0.642435", "ticker_sentiment_label": "Somewhat-Bullish", "ticker_sentiment_score": "0.308892"}, {"ticker": "KO", "relevance_score": "0.585793", "ticker_sentiment_label": "Somewhat-Bullish", "ticker_sentiment_score": "0.252750"}, {"ticker": "PEP", "relevance_score": "0.559311", "ticker_sentiment_label": "Somewhat-Bullish", "ticker_sentiment_score": "0.256949"}], "category_within_source": "General", "overall_sentiment_label": "Somewhat-Bullish", "overall_sentiment_score": 0.313174}'::jsonb, 'endpoint=news_sentiment/symbol=KO/dt=2026-06-06/response.json');
insert into raw.av_news_sentiment ("symbol", "url", "record", "source_s3_key") values ('KO', 'https://www.peta.org/about-peta/victories/coke-pepsi-and-campbell-soup-yank-funding-for-deadly-animal-experiments/', '{"url": "https://www.peta.org/about-peta/victories/coke-pepsi-and-campbell-soup-yank-funding-for-deadly-animal-experiments/", "title": "Coke, Pepsi, and Campbell Soup Yank Funding for Deadly Animal Experiments", "source": "PETA", "topics": [{"topic": "retail_wholesale", "relevance_score": "0.738497"}, {"topic": "finance", "relevance_score": "0.603653"}], "authors": [], "summary": "Following PETA''s intervention, five major food and beverage companies—PepsiCo. Inc., The Coca-Cola Company, Campbell Soup Company, Fresh Innovations, and Sensient Technologies—have ceased funding for animal experimentation. The companies were informed that their contributions were supporting cruel experiments at the University of Wisconsin–Madison’s Food Research Institute. The Coca-Cola Company has completely withdrawn sponsorship, while the others have imposed restrictions to prevent their money from funding animal tests.", "banner_image": null, "source_domain": "PETA", "time_published": "20241231T235959", "ticker_sentiment": [{"ticker": "PEP", "relevance_score": "1.000000", "ticker_sentiment_label": "Somewhat-Bullish", "ticker_sentiment_score": "0.318502"}, {"ticker": "KO", "relevance_score": "0.919386", "ticker_sentiment_label": "Somewhat-Bullish", "ticker_sentiment_score": "0.348973"}, {"ticker": "CPB", "relevance_score": "0.899011", "ticker_sentiment_label": "Somewhat-Bullish", "ticker_sentiment_score": "0.331970"}], "category_within_source": "General", "overall_sentiment_label": "Somewhat-Bullish", "overall_sentiment_score": 0.318145}'::jsonb, 'endpoint=news_sentiment/symbol=KO/dt=2026-06-06/response.json');
insert into raw.av_news_sentiment ("symbol", "url", "record", "source_s3_key") values ('KO', 'https://www.detroitnews.com/story/business/2024/03/19/pepsico-to-replace-coca-cola-at-subways-us-locations/73027754007/', '{"url": "https://www.detroitnews.com/story/business/2024/03/19/pepsico-to-replace-coca-cola-at-subways-us-locations/73027754007/", "title": "PepsiCo to replace Coca-Cola at Subway’s US locations", "source": "The Detroit News", "topics": [{"topic": "retail_wholesale", "relevance_score": "0.804703"}], "authors": ["Brett Pulley"], "summary": "PepsiCo Inc. has secured a 10-year agreement to become the exclusive beverage provider for all Subway sandwich shops in the US, replacing Coca-Cola Co. Coca-Cola brands will start to be phased out in January 2025. This deal also extends PepsiCo''s Frito-Lay agreement to supply snacks to Subway through 2030, reinforcing PepsiCo''s presence in one of the nation''s largest restaurant chains.", "banner_image": null, "source_domain": "The Detroit News", "time_published": "20241231T235959", "ticker_sentiment": [{"ticker": "PEP", "relevance_score": "1.000000", "ticker_sentiment_label": "Bullish", "ticker_sentiment_score": "0.404964"}, {"ticker": "KO", "relevance_score": "0.982829", "ticker_sentiment_label": "Bearish", "ticker_sentiment_score": "-0.427770"}], "category_within_source": "General", "overall_sentiment_label": "Neutral", "overall_sentiment_score": 0.001483}'::jsonb, 'endpoint=news_sentiment/symbol=KO/dt=2026-06-06/response.json');
insert into raw.av_news_sentiment ("symbol", "url", "record", "source_s3_key") values ('KO', 'https://www.businesswire.com/news/home/20241017466304/en/Netflix-Executive-Bela-Bajaria-Elected-to-Board-of-Directors-of-The-Coca-Cola-Company', '{"url": "https://www.businesswire.com/news/home/20241017466304/en/Netflix-Executive-Bela-Bajaria-Elected-to-Board-of-Directors-of-The-Coca-Cola-Company", "title": "Netflix Executive Bela Bajaria Elected to Board of Directors of The Coca-Cola Company", "source": "Business Wire", "topics": [{"topic": "finance", "relevance_score": "0.801212"}, {"topic": "retail_wholesale", "relevance_score": "0.741323"}], "authors": [], "summary": "Bela Bajaria, Chief Content Officer for Netflix Inc., has been elected to The Coca-Cola Company''s board of directors, effective immediately, bringing the board to 12 directors. Bajaria oversees all television and film for Netflix and manages a content budget of about $17 billion annually, bringing extensive global business and media experience to Coca-Cola. The company also declared a regular quarterly dividend of 48.5 cents per common share, payable Dec. 16.", "banner_image": null, "source_domain": "Business Wire", "time_published": "20241231T235959", "ticker_sentiment": [{"ticker": "NFLX", "relevance_score": "0.858303", "ticker_sentiment_label": "Somewhat-Bullish", "ticker_sentiment_score": "0.234298"}, {"ticker": "KO", "relevance_score": "1.000000", "ticker_sentiment_label": "Somewhat-Bullish", "ticker_sentiment_score": "0.346017"}], "category_within_source": "General", "overall_sentiment_label": "Somewhat-Bullish", "overall_sentiment_score": 0.27246}'::jsonb, 'endpoint=news_sentiment/symbol=KO/dt=2026-06-06/response.json');
