insert into raw.av_news_sentiment ("symbol", "url", "record", "source_s3_key") values ('KO', 'https://olympics.com/ioc/news/coca-cola-to-celebrate-everyday-greatness-for-paris-2024-as-it-announces-global-athlete-team-for-olympic-and-paralympic-games', '{"url": "https://olympics.com/ioc/news/coca-cola-to-celebrate-everyday-greatness-for-paris-2024-as-it-announces-global-athlete-team-for-olympic-and-paralympic-games", "title": "Coca-Cola to “Celebrate Everyday Greatness” for Paris 2024 as it announces global athlete team for Olympic and Paralympic Games", "source": "Olympics.com", "topics": [{"topic": "retail_wholesale", "relevance_score": "0.806218"}], "authors": [], "summary": "Coca-Cola has announced \"Celebrate Everyday Greatness\" as its theme for the Paris 2024 Olympic and Paralympic Games and unveiled its global roster of Team Coca-Cola athletes. The campaign aims to champion everyday moments that lead to greatness, featuring diverse athletes like Athing Mu and Kadeena Cox. As a Worldwide Partner, Coca-Cola will refresh athletes, officials, and spectators and continue its long-standing association with the Olympic Movement.", "banner_image": null, "source_domain": "Olympics.com", "time_published": "20241231T235959", "ticker_sentiment": [{"ticker": "KO", "relevance_score": "1.000000", "ticker_sentiment_label": "Bullish", "ticker_sentiment_score": "0.484836"}], "category_within_source": "General", "overall_sentiment_label": "Bullish", "overall_sentiment_score": 0.481118}'::jsonb, 'endpoint=news_sentiment/symbol=KO/dt=2026-06-06/response.json');
