-- AUTO-GENERATED CI fixture: minimal raw.* data so dbt can build in CI
-- against an ephemeral Postgres (no RDS/AV). Single active symbol (KO).
create schema if not exists raw;

CREATE TABLE IF NOT EXISTS raw.av_daily_prices (
    "symbol" text NOT NULL,
    "date" text NOT NULL,
    "record" jsonb NOT NULL,
    "source_s3_key" text,
    "loaded_at" timestamptz NOT NULL DEFAULT now(),
    CONSTRAINT av_daily_prices_pk PRIMARY KEY ("symbol", "date")
);

